import os
import joblib
import requests

class ModelLoader:
    def __init__(self):
        self.model_path = os.environ.get('MODEL_PATH')
        self.model = self.load_model()

    def load_model(self):
        if not self.model_path:
            raise ValueError("MODEL_PATH environment variable not set")
        
        # Fetch latest model version
        response = requests.get(self.model_path)
        if response.status_code == 200:
            model_data = response.content
            model = joblib.load(model_data)
            return model
        else:
            raise Exception("Failed to fetch model from the provided path")

# Usage
